1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const ALIKE_BLOCK_SIZE = 3;
10	const ALIKE_BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
35	type Damage = { itemType: string; amount: number };
36	type Incident = { cause: string; damages: Damage[] };
37	type QuoteStep = { op: "quote"; items: Item[] };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	type Step = QuoteStep | ClaimStep;
40	type Customer = { yearsWithMHPCO: number };
41	type Scenario = { customer: Customer; steps: Step[] };
42	type Policy = { items: Item[]; cap: number };
43	
44	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUM;
45	
46	const assertKnownItemTypes = (items: Item[]): void => {
47	  for (const item of items) {
48	    if (!isKnownItemType(item.type)) {
49	      throw new Error(`Unknown item type: ${item.type}`);
50	    }
51	  }
52	};
53	
54	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
55	
56	const groupByType = (items: Item[]): Item[][] => {
57	  const groups = Map.groupBy(items, (item) => item.type);
58	  return Array.from(groups.values());
59	};
60	
61	const sumBasePremiums = (items: Item[]): number =>
62	  items.reduce((acc, item) => acc + basePremiumOf(item), 0);
63	
64	const basePremiumForGroup = (group: Item[]): number =>
65	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
66	
67	const basePremiumForItems = (items: Item[]): number =>
68	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
69	
70	const cursedSurcharge = (item: Item): number =>
71	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
72	
73	const highEnchantmentSurcharge = (item: Item): number =>
74	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
75	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
76	    : 0;
77	
78	const itemSurcharges = (items: Item[]): number =>
79	  items.reduce(
80	    (sum, item) => sum + cursedSurcharge(item) + highEnchantmentSurcharge(item),
81	    0,
82	  );
83	
84	const firstInsuranceSurcharge = (basePremium: number): number =>
85	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
86	
87	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
88	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
89	
90	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
91	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
92	
93	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
94	  const basePremium = basePremiumForItems(items);
95	  return (
96	    Math.ceil(
97	      basePremium +
98	        itemSurcharges(items) +
99	        firstInsuranceSurcharge(basePremium) -
100	        loyaltyDiscount(basePremium, customer) -
101	        followUpDiscount(basePremium, isFollowUp),
102	    ) + PROCESSING_FEE
103	  );
104	};
105	
106	const insuranceSum = (items: Item[]): number =>
107	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
108	
109	const reimbursableAmount = (item: Item, damageAmount: number): number =>
110	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
111	    ? damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE
112	    : damageAmount;
113	
114	const payoutForDamage = (item: Item, damage: Damage): number =>
115	  reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
116	
117	const openPolicy = (items: Item[]): Policy => ({
118	  items,
119	  cap: insuranceSum(items) * CAP_MULTIPLIER,
120	});
121	
122	const findItem = (policy: Policy, itemType: string): Item =>
123	  policy.items.find((i) => i.type === itemType) as Item;
124	
125	const countDamagesByType = (damages: Damage[]): Map<string, number> => {
126	  const counts = new Map<string, number>();
127	  for (const damage of damages) {
128	    counts.set(damage.itemType, (counts.get(damage.itemType) ?? 0) + 1);
129	  }
130	  return counts;
131	};
132	
133	const policyItemCount = (policy: Policy, itemType: string): number =>
134	  policy.items.filter((item) => item.type === itemType).length;
135	
136	const assertDamagesCoveredByPolicy = (policy: Policy, damages: Damage[]): void => {
137	  for (const [itemType, count] of countDamagesByType(damages)) {
138	    if (count > policyItemCount(policy, itemType)) {
139	      throw new Error(`Damage references item not in policy: ${itemType}`);
140	    }
141	  }
142	};
143	
144	const settleClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
145	  const payoutFor = (damage: Damage) => payoutForDamage(findItem(policy, damage.itemType), damage);
146	  const desiredPayout = incident.damages.reduce((sum, damage) => sum + payoutFor(damage), 0);
147	  const payout = Math.floor(Math.min(desiredPayout, policy.cap));
148	  return { payout, remainingCap: policy.cap - payout };
149	};
150	
151	export const runScenario = (scenario: Scenario): unknown => {
152	  const policies: Policy[] = [];
153	
154	  const handleQuote = (step: QuoteStep) => {
155	    assertKnownItemTypes(step.items);
156	    const isFollowUp = policies.length > 0;
157	    policies.push(openPolicy(step.items));
158	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
159	  };
160	
161	  const handleClaim = (step: ClaimStep) => {
162	    const policy = policies[step.policy];
163	    for (const damage of step.incident.damages) {
164	      if (damage.amount < 0) {
165	        throw new Error(`Negative damage amount: ${damage.amount}`);
166	      }
167	    }
168	    assertDamagesCoveredByPolicy(policy, step.incident.damages);
169	    const result = settleClaim(policy, step.incident);
170	    policies[step.policy] = { ...policy, cap: result.remainingCap };
171	    return result;
172	  };
173	
174	  const results = scenario.steps.map((step) =>
175	    step.op === "claim" ? handleClaim(step) : handleQuote(step),
176	  );
177	  return { results };
178	};
